import uuid from django.db import models
class BaseModel(models.Model): uid = models.UUIDField(default=uuid.uuid4, unique=True, editable=False) created_at = models.DateTimeField(auto_now_add=True) updated_at = models.DateTimeField(auto_now=True)
class Meta: abstract = True

from django.db import transaction
from .models import User, UserType


def create_user(email: str, name: str, *, user_type: str = UserType.REGULAR) -> User:
    return User.objects.create(email=email, name=name, user_type=user_type)


@transaction.atomic
def transfer_ownership(from_user: User, to_user: User, item_id: int) -> None:
    from apps.items import models as item_models
    item = item_models.Item.objects.select_for_update().get(id=item_id)
    item.owner = to_user
    item.save(update_fields=["owner", "updated_at"])
